+fn parse_u64_full_arg(arg: &[u8]) -> Result<u64, CommandError> {
+    let slen = arg.len();
+    if slen == 0 || slen > 20 {
+        return Err(CommandError::InvalidInteger);
+    }
+    if slen == 1 && arg[0] == b'0' {
+        return Ok(0);
+    }
+    if arg[0] < b'1' || arg[0] > b'9' {
+        return Err(CommandError::InvalidInteger);
+    }
+
+    let mut v: u64 = (arg[0] - b'0') as u64;
+    for &b in &arg[1..] {
+        if !b.is_ascii_digit() {
+            return Err(CommandError::InvalidInteger);
+        }
+        if v > (u64::MAX / 10) {
+            return Err(CommandError::InvalidInteger);
+        }
+        v *= 10;
+        let digit = (b - b'0') as u64;
+        if v > (u64::MAX - digit) {
+            return Err(CommandError::InvalidInteger);
+        }
+        v += digit;
+    }
+
+    Ok(v)
+}
